import anthropic, os
from typing import Union

def build_claude_client() -> tuple[Union[anthropic.Anthropic, anthropic.AnthropicBedrock, anthropic.AnthropicVertex], str]:
    """
    Returns (client, model_id) based on environment configuration.
    Swap CLAUDE_PLATFORM to change deployment without touching business logic.
    """
    platform = os.environ.get("CLAUDE_PLATFORM", "direct")
    model_base = "claude-opus-4-8"

    if platform == "direct":
        return (
            anthropic.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"]),
            model_base,
        )
    elif platform == "bedrock":
        region = os.environ.get("CLAUDE_REGION", "us-east-1")
        return (
            anthropic.AnthropicBedrock(aws_region=region),
            f"anthropic.{model_base}",
        )
    elif platform == "vertex":
        return (
            anthropic.AnthropicVertex(
                region=os.environ.get("CLAUDE_REGION", "us-central1"),
                project_id=os.environ["GCP_PROJECT_ID"],
            ),
            f"{model_base}@20251101",
        )
    else:
        raise ValueError(f"Unknown CLAUDE_PLATFORM: {platform}")

client, model = build_claude_client()
